// Component interface (base class)
class Notifier {
  send(message) {
    throw new Error('send() must be implemented');
  }
}

// Concrete Component
class EmailNotifier extends Notifier {
  constructor(email) {
    super();
    this.email = email;
  }

  send(message) {
    console.log(`Email to ${this.email}: ${message}`);
  }
}

// Base Decorator
class NotifierDecorator extends Notifier {
  #wrapped;

  constructor(notifier) {
    super();
    this.#wrapped = notifier;
  }

  send(message) {
    this.#wrapped.send(message);
  }
}

// Concrete Decorators
class SMSDecorator extends NotifierDecorator {
  constructor(notifier, phone) {
    super(notifier);
    this.phone = phone;
  }

  send(message) {
    super.send(message);
    console.log(`SMS to ${this.phone}: ${message}`);
  }
}

class SlackDecorator extends NotifierDecorator {
  constructor(notifier, channel) {
    super(notifier);
    this.channel = channel;
  }

  send(message) {
    super.send(message);
    console.log(`Slack #${this.channel}: ${message}`);
  }
}

// Usage
let notifier = new EmailNotifier('user@example.com');
notifier = new SMSDecorator(notifier, '+1234567890');
notifier = new SlackDecorator(notifier, 'alerts');

notifier.send('Server is down!');
// Email to user@example.com: Server is down!
// SMS to +1234567890: Server is down!
// Slack #alerts: Server is down!

